import React from 'react';
import DiscountChart from './components/DiscountChart';

function App() {
  const chartConfigs = [
    { tableName: 'PLS - DiscountCharts', title: 'pMaxi' },
    { tableName: 'HEX - DiscountCharts', title: 'HEX' },
    // Add more configurations for other datasets
  ];

  return (
    <div className="App">
      {chartConfigs.map((config, index) => (
        <DiscountChart 
          key={index}
          tableName={config.tableName}
          title={config.title}
        />
      ))}
    </div>
  );
}

export default App;
